What does this program print?

```cpp
#include <iostream>
int main() {
    int a = 10;
    int b = 3;
    std::cout << a / b << "\n";
    std::cout << a % b << "\n";
    std::cout << (a > b ? a : b) << "\n";
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
int main() {
    int x = 0;
    bool r1 = (x != 0) && (10 / x > 1);
    bool r2 = (x == 0) || (10 / x > 1);
    std::cout << r1 << "\n";
    std::cout << r2 << "\n";
    return 0;
}
```

